```
#include "mainwindow.h"
#include "ui_mainwindow.h"

MainWindow::MainWindow(QWidget *parent)
    : QMainWindow(parent)
    , ui(new Ui::MainWindow)
{
    ui->setupUi(this);

    listView = new QListView(this);
    model = new QStandardItemModel(this);

    QStandardItem *item1 = new QStandardItem("菜单1");
    model->appendRow(item1);
    QStandardItem *item2 = new QStandardItem("菜单2");
    model->appendRow(item2);

    // 为菜单1添加子菜单
    QStandardItem *subitem11 = new QStandardItem("子菜单1");
    item1->appendRow(subitem11);
    QStandardItem *subitem12 = new QStandardItem("子菜单2");
    item1->appendRow(subitem12);

    // 设置菜单1为可展开项
    item1->setData(QVariant(true), Qt::UserRole);

    listView->setModel(model);
    setCentralWidget(listView);

    connect(listView, SIGNAL(clicked(QModelIndex)),
            this, SLOT(onListViewClicked(QModelIndex)));
}

MainWindow::~MainWindow()
{
    delete ui;
}

void MainWindow::onListViewClicked(const QModelIndex &index)
{
    QModelIndex parentIndex = index.parent();
    QModelIndex childIndex = index;

    // 如果点击的是子菜单
    if (parentIndex.isValid()) {
        QString text = model->itemFromIndex(parentIndex)->text();

        // 如果点击的是菜单1的子菜单
        if (text == "菜单1") {
            // 根据点击的子菜单的索引判断是哪个子菜单
            switch(childIndex.row()) {
            case 0:
                qDebug() << "子菜单1被点击";
                break;
            case 1:
                qDebug() << "子菜单2被点击";
                break;
            default:
                break;
            }
        }
    }
    // 如果点击的是菜单，而不是子菜单
    else {
        QString text = model->itemFromIndex(index)->text();

        // 如果点击的是菜单1
        if (text == "菜单1") {
            bool expanded = listView->isExpanded(index);

            // 如果菜单1已经展开了，那么收起子菜单
            if (expanded) {
                listView->setExpanded(index, false);
            }
            // 如果菜单1没展开，那么展开菜单1
            else {
                listView->setExpanded(index, true);
            }
        }
    }
}
