在Qt中，我们可以使用QTreeView控件来实现二级菜单。QTreeView是一种展示多级树形结构的控件，可以用来显示二级列表中的数据。以下是一个简单的示例代码：

```
#include <QApplication>
#include <QTreeView>
#include <QStandardItemModel>
#include <QStandardItem>

int main(int argc, char *argv[])
{
    QApplication app(argc, argv);

    // 创建QTreeView控件
    QTreeView *treeView = new QTreeView();
    treeView->setWindowTitle("二级菜单");

    // 创建QStandardItemModel模型
    QStandardItemModel *model = new QStandardItemModel();

    for (int i = 1; i <= 2; ++i) {
        // 创建一级节点
        QStandardItem *parentItem = new QStandardItem(tr("菜单%1").arg(i));

        // 如果该节点有子节点，则需要设置标志位，表示该节点可展开
        parentItem->setFlags(Qt::ItemIsEnabled | Qt::ItemIsSelectable | Qt::ItemIsUserCheckable | Qt::ItemIsEditable | Qt::ItemIsTristate);
        if (i == 1) {
            for (int j = 1; j <= 2; ++j) {
                // 创建二级节点
                QStandardItem *childItem = new QStandardItem(tr("菜单%1-%2").arg(i).arg(j));
                childItem->setFlags(Qt::ItemIsEnabled | Qt::ItemIsSelectable | Qt::ItemIsUserCheckable | Qt::ItemIsEditable);
                parentItem->appendRow(childItem);
            }
        } else {
            QStandardItem *childItem = new QStandardItem(tr("菜单%1-1").arg(i));
            childItem->setFlags(Qt::ItemIsEnabled | Qt::ItemIsSelectable | Qt::ItemIsUserCheckable | Qt::ItemIsEditable);
            parentItem->appendRow(childItem);

            childItem = new QStandardItem(tr("菜单%1-2").arg(i));
            childItem->setFlags(Qt::ItemIsEnabled | Qt::ItemIsSelectable | Qt::ItemIsUserCheckable | Qt::ItemIsEditable);
            parentItem->appendRow(childItem);

            childItem = new QStandardItem(tr("菜单%1-3").arg(i));
            childItem->setFlags(Qt::ItemIsEnabled | Qt::ItemIsSelectable | Qt::ItemIsUserCheckable | Qt::ItemIsEditable);
            parentItem->appendRow(childItem);
        }
        model->appendRow(parentItem);
    }

    // 将QTreeView控件和QStandardItemModel模型对象关联起来
    treeView->setModel(model);

    // 显示QTreeView控件
    treeView->show();

    return app.exec();
}
```

